// Analyze SEO health of Squarespace pages
const data = $input.first().json;
const pages = data.pages || data.result || [];

const seoReport = [];

for (const page of pages) {
  const title = page.title || page.pageName || 'Untitled';
  const url = page.fullUrl || page.url || 'unknown';
  const seoDescription = page.seoData?.seoDescription || '';
  const seoTitle = page.seoData?.seoTitle || title;

  const issues = [];
  let score = 100;

  // Check SEO title length (optimal 50-60 chars)
  if (!seoTitle || seoTitle.length < 30) {
    issues.push('SEO title too short (< 30 chars)');
    score -= 15;
  } else if (seoTitle.length > 65) {
    issues.push('SEO title too long (> 65 chars, may truncate in SERPs)');
    score -= 10;
  }

  // Check meta description
  if (!seoDescription) {
    issues.push('Missing meta description');
    score -= 20;
  } else if (seoDescription.length < 70) {
    issues.push('Meta description too short (< 70 chars)');
    score -= 10;
  } else if (seoDescription.length > 160) {
    issues.push('Meta description too long (> 160 chars, may truncate)');
    score -= 5;
  }

  // Check for basic keywords in title
  const keyPhrases = ['service', 'location', 'contact', 'about', 'pricing'];
  let keywordCount = 0;
  for (const phrase of keyPhrases) {
    if ((title + seoDescription).toLowerCase().includes(phrase)) {
      keywordCount++;
    }
  }
  if (keywordCount < 2) {
    issues.push('Low keyword diversity — consider adding location/service terms');
    score -= 10;
  }

  // Slug quality check
  if (url && url.length > 75) {
    issues.push('URL slug too long (> 75 chars)');
    score -= 5;
  }

  seoReport.push({
    page_id: page.id || 'unknown',
    title: title,
    url: url,
    seo_title: seoTitle,
    seo_description: seoDescription,
    seo_score: Math.max(0, score),
    issues: issues,
    needs_optimization: issues.length > 0
  });
}

const pagesNeedingWork = seoReport.filter(p => p.needs_optimization);
const avgScore = seoReport.length > 0 
  ? Math.round(seoReport.reduce((sum, p) => sum + p.seo_score, 0) / seoReport.length) 
  : 100;

return {
  pages_analyzed: seoReport.length,
  average_seo_score: avgScore,
  pages_needing_optimization: pagesNeedingWork.length,
  page_details: pagesNeedingWork,
  all_pages: seoReport,
  client_id: $env.CLIENT_ID || 'unknown',
  site_id: $env.SQUARESPACE_SITE_ID || 'unknown'
};

// Build SEO optimization prompt
const data = $input.first().json;
const clientName = $env.CLIENT_NAME || 'our client';
const businessType = $env.CLIENT_BUSINESS_TYPE || 'small business';
const location = $env.CLIENT_LOCATION || 'Australia';

let pageDetailsText = '';
for (const page of data.page_details.slice(0, 10)) {
  pageDetailsText += `\n- Page: "${page.title}" (${page.url})\n`;
  pageDetailsText += `  Current SEO Title: "${page.seo_title}"\n`;
  pageDetailsText += `  Current Meta: "${page.seo_description}"\n`;
  pageDetailsText += `  Score: ${page.seo_score}/100\n`;
  pageDetailsText += `  Issues: ${page.issues.join('; ')}\n`;
}

const prompt = `You are an SEO specialist for Squarespace websites. Client: ${clientName}, a ${businessType} based in ${location}.

Squarespace SEO Audit Results:
- Pages Analyzed: ${data.pages_analyzed}
- Average SEO Score: ${data.average_seo_score}/100
- Pages Needing Optimization: ${data.pages_needing_optimization}

Problem Pages:
${pageDetailsText}

Provide optimization recommendations:
1. For each page, write an improved SEO title (50-60 chars) and meta description (120-155 chars) that:
   - Includes relevant keywords naturally
   - Mentions the business location for local SEO
   - Has a clear call to action
   - Is unique across all pages
2. Suggest any URL slug improvements (keep short, descriptive, hyphenated)
3. Recommend internal linking opportunities between these pages

Respond in JSON format:
{
  "overall_assessment": "summary",
  "page_recommendations": [
    {
      "page_id": "id",
      "page_title": "title",
      "improved_seo_title": "new title",
      "improved_meta_description": "new description",
      "suggested_slug": "if change needed",
      "priority": "high/medium/low"
    }
  ],
  "local_seo_tips": ["tip1", "tip2"],
  "internal_linking_suggestions": ["suggestion1"]
}`;

return {
  task_type: 'analysis',
  user_message: prompt,
  context: `Squarespace SEO audit for ${clientName}. Site ID: ${$env.SQUARESPACE_SITE_ID}`
};

// Process approved SEO changes and apply to Squarespace
// Squarespace API: PUT /1.0/sites/{site_id}/pages/{page_id}
const approval = $input.first().json;
const approvedChanges = approval.approved_changes || [];

if (approvedChanges.length === 0) {
  return { status: 'no_changes_approved', message: 'No SEO changes were approved.' };
}

// Map to API-compatible update payloads
const updatePayloads = [];
const siteId = $env.SQUARESPACE_SITE_ID;

for (const change of approvedChanges) {
  updatePayloads.push({
    page_id: change.page_id,
    url: `https://api.squarespace.com/1.0/sites/${siteId}/pages/${change.page_id}`,
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${$env.SQUARESPACE_API_KEY}`
    },
    body: {
      seoData: {
        seoTitle: change.improved_seo_title,
        seoDescription: change.improved_meta_description
      }
    }
  });
}

return {
  status: 'applying',
  changes_count: updatePayloads.length,
  update_payloads: updatePayloads,
  applied_at: new Date().toISOString(),
  client_id: $env.CLIENT_ID
};
